import React, { useState, useContext } from 'react';
import {
  Box, Card, CardContent, TextField, Button, Typography,
  Link, Alert, CircularProgress, InputAdornment, IconButton, Stack,
} from '@mui/material';
import { Visibility, VisibilityOff } from '@mui/icons-material';
import { Link as RouterLink, useNavigate } from 'react-router-dom';
import { registerUser } from '../api';
import { AuthContext } from '../context/AuthContext';

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function SignupPage() {
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();
  const [form, setForm] = useState({ username: '', email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [emailError, setEmailError] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));

    if (name === 'email') {
      setEmailError(value && !EMAIL_REGEX.test(value) ? 'Enter a valid email address' : '');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!form.username.trim()) {
      setError('Username is required.');
      return;
    }

    if (!form.email || !EMAIL_REGEX.test(form.email)) {
      setEmailError('Enter a valid email address');
      return;
    }

    if (form.password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }

    setError('');
    setLoading(true);
    try {
      const { data } = await registerUser(form);
      login(data.token);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.msg || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const isValid =
    form.username.trim().length > 0 &&
    form.email.trim().length > 0 &&
    EMAIL_REGEX.test(form.email) &&
    form.password.length >= 6;

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #0f0f1a 0%, #1a1a2e 50%, #16213e 100%)',
        px: 2,
      }}
    >
      <Box sx={{
        position: 'fixed', top: '-10%', right: '-10%', width: 400, height: 400,
        borderRadius: '50%', background: 'rgba(108,99,255,0.12)', filter: 'blur(80px)', zIndex: 0,
      }} />
      <Box sx={{
        position: 'fixed', bottom: '-10%', left: '-10%', width: 350, height: 350,
        borderRadius: '50%', background: 'rgba(255,101,132,0.10)', filter: 'blur(80px)', zIndex: 0,
      }} />

      <Card sx={{
        width: '100%', maxWidth: 420, zIndex: 1,
        backdropFilter: 'blur(20px)',
        background: 'rgba(26,26,46,0.85)',
        boxShadow: '0 24px 60px rgba(0,0,0,0.4)',
      }}>
        <CardContent sx={{ p: 4 }}>
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Typography variant="h4" sx={{
              background: 'linear-gradient(135deg, #6C63FF, #FF6584)',
              WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
              fontWeight: 800, letterSpacing: '-0.5px',
            }}>
              ConnectSphere
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Create your account and join the sphere.
            </Typography>
          </Box>

          {error && <Alert severity="error" sx={{ mb: 2, borderRadius: 2 }}>{error}</Alert>}

          <Box component="form" onSubmit={handleSubmit} noValidate>
            <TextField
              fullWidth label="Username" name="username"
              value={form.username} onChange={handleChange}
              required autoComplete="username" sx={{ mb: 2 }}
            />
            <TextField
              fullWidth label="Email Address" name="email" type="email"
              value={form.email} onChange={handleChange}
              required autoComplete="email" sx={{ mb: 2 }}
            />
            <TextField
              fullWidth label="Password" name="password"
              type={showPassword ? 'text' : 'password'}
              value={form.password} onChange={handleChange}
              required helperText="At least 6 characters" sx={{ mb: 3 }}
              InputProps={{
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton onClick={() => setShowPassword(!showPassword)} edge="end">
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />
            <Button
              type="submit" fullWidth variant="contained" size="large"
              disabled={loading || !isValid}
              sx={{ mb: 2, py: 1.4 }}
            >
              {loading ? <CircularProgress size={22} color="inherit" /> : 'Create Account'}
            </Button>
          </Box>

          <Typography align="center" variant="body2" color="text.secondary">
            Already have an account?{' '}
            <Link component={RouterLink} to="/login" sx={{ color: '#6C63FF', fontWeight: 600 }}>
              Sign In
            </Link>
          </Typography>
        </CardContent>
      </Card>
    </Box>
  );
}
